import { MapContainer, TileLayer } from "react-leaflet";
import { useEffect, useState } from "react";
import PlaneMarker from "../components/PlaneMarker";
import "leaflet/dist/leaflet.css";
import "./Dashboard.css";

export default function Dashboard() {
  const [planes, setPlanes] = useState([]);
  const [selectedPlane, setSelectedPlane] = useState(null);

  const fetchFlights = async () => {
    try {
      // India bounding box
      const res = await fetch(
        "https://opensky-network.org/api/states/all?lamin=6&lomin=68&lamax=35&lomax=97"
      );
      const data = await res.json();

      const validFlights = data.states.filter(
        (f) => f[5] && f[6] // has longitude + latitude
      );

      setPlanes(validFlights.slice(0, 20)); // limit for performance
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    fetchFlights();
    const interval = setInterval(fetchFlights, 8000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="dashboard">
      <div className="panel">
        ✈️ Live Flights (Click a plane)
      </div>

      <MapContainer center={[20, 77]} zoom={5} className="map">
        <TileLayer url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png" />

        {planes.map((plane, index) => (
          <PlaneMarker
            key={index}
            position={[plane[6], plane[5]]}
            flightData={{
              callsign: plane[1],
              velocity: plane[9],
              altitude: plane[7],
            }}
          />
        ))}
      </MapContainer>
    </div>
  );
}
